import { test, expect } from '@playwright/test';

test('verify navigation links in mobile header', async ({ page }) => {
  // Set viewport to mobile 375x812
  await page.setViewportSize({ width: 375, height: 812 });

  // Navigate to the home page
  await page.goto('http://localhost:3002/');

  // Verify links in header
  const brandLink = page.getByRole('link', { name: 'okwasniewski' });
  const blogLink = page.getByRole('link', { name: 'blog' });
  const portfolioLink = page.getByRole('link', { name: 'portfolio' });
  const videosLink = page.getByRole('link', { name: 'videos' });
  const contactLink = page.getByRole('link', { name: 'contact' });

  // Assert existence and hrefs
  await expect(brandLink).toBeVisible();
  await expect(brandLink).toHaveAttribute('href', '/');
  await expect(blogLink).toBeVisible();
  await expect(blogLink).toHaveAttribute('href', '/blog');
  await expect(portfolioLink).toBeVisible();
  await expect(portfolioLink).toHaveAttribute('href', '/portfolio');
  await expect(videosLink).toBeVisible();
  await expect(videosLink).toHaveAttribute('href', '/videos');

  // Validate navigation for existing links
  await blogLink.click();
  await expect(page).toHaveURL('http://localhost:3002/blog');

  await portfolioLink.click();
  await expect(page).toHaveURL('http://localhost:3002/portfolio');

  await videosLink.click();
  await expect(page).toHaveURL('http://localhost:3002/videos');

  await brandLink.click();
  await expect(page).toHaveURL('http://localhost:3002/');

  // Check for the failing 'contact' link on the home page
  // It is expected to be a link and route to /contact
  await expect(page.getByRole('link', { name: 'contact' })).toBeVisible();
  await expect(page.getByRole('link', { name: 'contact' })).toHaveAttribute('href', '/contact');
});
